  .box{border:var(--wobbly-border);border-radius:var(--wobbly-radius);padding:4vh 5vw;background:white;box-shadow:10px 10px 0 rgba(0,0,0,.05);margin:2vh 0;width:100%;max-width:85vw}
  .blue{color:var(--blue-marker);border-color:var(--blue-marker)!important}
  .green{color:var(--green-marker);border-color:var(--green-marker)!important}
  .red{color:var(--red-marker);border-color:var(--red-marker)!important}
  .orange{color:var(--orange-marker);border-color:var(--orange-marker)!important}
  ul{list-style:none;padding-left:1vw}
  li{margin-bottom:2.5vh;position:relative;padding-left:5vw;font-size:3.8vw;line-height:1.2}
  li::before{content:"→";position:absolute;left:0;top:0;font-size:3.8vw;opacity:.6}
  .vector-space{position:relative;width:64vw;height:39vh;border-left:3px solid var(--ink);border-bottom:3px solid var(--ink);margin:1vh 0 0}
  .point{position:absolute;width:14px;height:14px;background:var(--ink);border-radius:50%;transform:translate(-50%,50%)}
  .query-point{width:20px;height:20px;border:4px solid var(--red-marker);background:white}
  .point-small{width:11px;height:11px;opacity:.76}
  .point-far{width:10px;height:10px;opacity:.22}
  .label-node{position:absolute;font-size:2.25vw;font-family:var(--hand);white-space:nowrap;line-height:1}
  .label-above{transform:translate(-50%,-130%)}
  .label-below{transform:translate(-50%,145%)}
  .label-right{transform:translate(18px,-45%)}
  .tiny-label{font-size:1.3vw;opacity:.55}
  .axis-hint{position:absolute;font-family:var(--mono);font-size:1.25vw;opacity:.28}
  .rag-loop{display:grid;grid-template-columns:minmax(0,1fr) auto minmax(0,1fr) auto minmax(0,1fr);align-items:center;gap:1.1vw;text-align:center;transform:rotate(-1deg);padding:6vh 2.5vw;max-width:90vw}
  .rag-loop-word{font-family:var(--hand-title);font-size:clamp(64px,6.4vw,124px);line-height:.9;white-space:nowrap;letter-spacing:0}
  .rag-loop-arrow{font-size:clamp(44px,4vw,78px);opacity:.35;line-height:1}
  #nav{position:fixed;left:50%;bottom:3vh;transform:translateX(-50%);z-index:30;display:flex;gap:12px}
  #nav .dot{width:14px;height:14px;border-radius:50%;background:rgba(0,0,0,.1);cursor:pointer;border:0}
  #nav .dot.active{background:rgba(0,0,0,.8);width:30px;border-radius:999px}
</style>
</head>
<body>
<div id="deck">

<section class="slide">
  <div class="chrome"><div>RAG Intro</div><div>01 / 05</div></div>
  <h1 class="h-hero">RAG: How AI Reads</h1>
  <p class="h-sub">Retrieval, Augmented, Generation.</p>
  <div class="box" style="transform:rotate(2deg);text-align:center">
    <p style="font-size:5vw">"Reliable AI = Brain + Library"</p>
  </div>
</section>

<section class="slide">
  <div class="chrome"><div>R is for...</div><div>02 / 05</div></div>
  <h2 class="h-xl blue">Retrieval</h2>
  <div class="box blue" style="display:flex;flex-direction:column;align-items:center">
    <div class="vector-space">
      <div class="axis-hint" style="left:2%;bottom:-26px">meaning map</div>
      <div class="axis-hint" style="right:0;bottom:-26px">more different →</div>

      <div class="point query-point" style="bottom:70%;left:22%"></div>
      <div class="label-node label-above red" style="bottom:70%;left:22%"><b>Your Query</b></div>

      <div class="point blue" style="bottom:61%;left:36%"></div>
      <div class="label-node label-right blue" style="bottom:61%;left:36%">Best Fact</div>

      <div class="point blue point-small" style="bottom:50%;left:18%"></div>
      <div class="label-node label-below blue tiny-label" style="bottom:50%;left:18%">Doc chunk</div>

      <div class="point green point-small" style="bottom:86%;left:42%"></div>
      <div class="label-node label-above green tiny-label" style="bottom:86%;left:42%">FAQ note</div>

      <div class="point green point-small" style="bottom:74%;left:55%"></div>
      <div class="label-node label-right green tiny-label" style="bottom:74%;left:55%">Manual bit</div>

      <div class="point blue point-small" style="bottom:36%;left:31%"></div>
      <div class="point green point-small" style="bottom:90%;left:29%"></div>
      <div class="point blue point-small" style="bottom:58%;left:49%"></div>

      <div class="point orange point-far" style="bottom:22%;left:76%"></div>
      <div class="label-node label-right orange tiny-label" style="bottom:22%;left:76%">Unrelated</div>
      <div class="point orange point-far" style="bottom:40%;left:88%"></div>
      <div class="point orange point-far" style="bottom:11%;left:61%"></div>
      <div class="point orange point-far" style="bottom:67%;left:83%"></div>

      <svg width="100%" height="100%" style="position:absolute;inset:0;pointer-events:none">
        <path d="M 22% 30% Q 29% 34% 36% 39%" fill="none" stroke="var(--red-marker)" stroke-width="3" stroke-dasharray="7,8" style="transform:scaleY(-1) translateY(-100%)"/>
        <path d="M 22% 30% Q 20% 41% 18% 50%" fill="none" stroke="var(--blue-marker)" stroke-width="2" stroke-dasharray="4,9" opacity=".42" style="transform:scaleY(-1) translateY(-100%)"/>
        <path d="M 22% 30% Q 33% 17% 42% 14%" fill="none" stroke="var(--green-marker)" stroke-width="2" stroke-dasharray="4,9" opacity=".42" style="transform:scaleY(-1) translateY(-100%)"/>
        <path d="M 22% 30% Q 40% 24% 55% 26%" fill="none" stroke="var(--green-marker)" stroke-width="2" stroke-dasharray="4,9" opacity=".28" style="transform:scaleY(-1) translateY(-100%)"/>
      </svg>
    </div>
    <p style="margin-top:4.8vh;font-size:3.35vw;text-align:center">
      <b>Retrieval picks nearby dots.</b><br>
      Far dots stay out of the prompt.
    </p>
  </div>
</section>

<section class="slide">
  <div class="chrome"><div>A is for...</div><div>03 / 05</div></div>
  <h2 class="h-xl green">Augmented</h2>
  <div class="box green" style="display:flex;flex-direction:column;gap:4vh;transform:rotate(1deg)">
    <h3 class="h-sub">Pasting the Data</h3>
    <div style="border:3px dashed var(--ink);padding:3vh;border-radius:15px;background:rgba(0,0,0,.02)">
      <p style="font-size:2vw;font-family:var(--mono);opacity:.5">[NEW PROMPT]</p>
      <p style="font-size:4vw;line-height:1.2">
        "Use this data: <b>{FACTS WE FOUND}</b><br>
        To answer this: <b>{YOUR QUESTION}</b>"
      </p>
    </div>
    <p style="text-align:center;font-size:3vw;opacity:.6">"The AI now has its notes open!"</p>
  </div>
</section>

<section class="slide">
  <div class="chrome"><div>G is for...</div><div>04 / 05</div></div>
  <h2 class="h-xl red">Generation</h2>
  <div class="box red" style="transform:rotate(-.5deg)">
    <div style="display:flex;justify-content:center;align-items:center;gap:5vw;margin-bottom:4vh">
      <div style="font-size:8vw">LLM</div>
      <div style="display:flex;flex-direction:column;align-items:center">
        <div style="font-family:var(--mono);font-size:2vw;margin-bottom:-1vh">GOT</div>
        <div style="font-size:5vw">→</div>
      </div>
      <div class="box green" style="background:var(--green-marker);color:white;padding:2vh 4vw;margin:0;width:auto"><b>TRUTH_</b></div>
    </div>
    <ul>
      <li>AI reads the provided notes</li>
      <li>Summarizes the real answer</li>
      <li>Zero "Hallucinations"</li>
      <li>Source-backed results</li>
    </ul>
  </div>
</section>

<section class="slide">
  <div class="chrome"><div>Summary</div><div>05 / 05</div></div>
  <h1 class="h-hero">The RAG Loop</h1>
  <div class="box rag-loop">
    <div class="blue rag-loop-word"><b>FETCH</b></div>
    <div class="rag-loop-arrow">→</div>
    <div class="green rag-loop-word"><b>PASTE</b></div>
    <div class="rag-loop-arrow">→</div>
    <div class="red rag-loop-word"><b>WRITE</b></div>
  </div>
  <p class="h-sub" style="margin-top:6vh">Smart. Reliable. Fast.</p>
</section>

</div>
<div id="nav"></div>
<script>
const deck=document.getElementById('deck');
const slides=deck.querySelectorAll('.slide');
const nav=document.getElementById('nav');
let idx=0,total=slides.length,lock=false;
slides.forEach((s,i)=>{
  const b=document.createElement('button');
  b.className='dot';
  b.onclick=()=>go(i);
  nav.appendChild(b);
});
function go(n){
  if(lock)return;
  idx=Math.max(0,Math.min(total-1,n));
  deck.style.transform=`translateX(${-idx*100}vw)`;
  nav.querySelectorAll('.dot').forEach((d,i)=>d.classList.toggle('active',i===idx));
  lock=true;setTimeout(()=>lock=false,600);
}
addEventListener('keydown',e=>{
  if(e.key==='ArrowRight'||e.key===' '||e.key==='PageDown')go(idx+1);
  if(e.key==='ArrowLeft'||e.key==='PageUp')go(idx-1);
});
go(0);
</script>
</body>
</html>
</artifact>
